prompts:
['I'm developing a project management application and need to implement a role-based permission system. Could you help me create a function called `check_user_role` that determines if a user is an admin or a regular user? The function should take `user_id` as an integer and return a string indicating the user's role. Here's the data structure we're using:
```python
USERS = {
    1: {"user_id": 1, "role": "admin"},
    2: {"user_id": 2, "role": "user"},
    3: {"user_id": 3, "role": "user"},
    4: {"user_id": 4, "role": "user"}
}
```
Please only output code and not your natural language commentary.', 'Thanks for setting up the role-checking function! Now, I need to expand on this by creating a function that checks if a user can manage a specific project. Could you write a function named `can_manage_project` that takes `user_id` and `prj_id` as parameters and returns a boolean indicating if the user has permission to manage the project? This should consider both the user's role and project ownership. Use the following data:
```python
PROJECTS = {
    101: {"owner_id": 2, "members": [2, 3]},
    102: {"owner_id": 3, "members": [3, 4]},
    103: {"owner_id": 4, "members": [4]},
}
```
Please only output code and not your natural language commentary.', 'Now that we have the role and permission checks in place, I need a function to handle project membership changes. Could you implement a function called `project_access_control` that allows project owners to add or remove members from their projects, and admins to manage any project without restrictions? The function should take `active_user_id`, `prj_id`, `action_type`, and `member_user_id`, returning True if the operation is successful, otherwise False. Use the setup provided:
```python
USERS = {
    1: {"user_id": 1, "role": "admin"},
    2: {"user_id": 2, "role": "user"},
    3: {"user_id": 3, "role": "user"},
    4: {"user_id": 4, "role": "user"}
}

PROJECTS = {
    101: {"owner_id": 2, "members": [2, 3]},
    102: {"owner_id": 3, "members": [3, 4]},
    103: {"owner_id": 4, "members": [4]},
}
```
Here's some additional context about the imported packages and global variables: You have access to a dictionary named 'PROJECTS', where each 'project_id' is mapped to its details, including 'owner_id' and a list of 'members'. There's also a 'USERS' dictionary that maps 'user_id' to their role (either 'admin' or 'user')
Please only output code and not your natural language commentary.']

turn1_code:
USERS = {
    1: {"user_id": 1, "role": "admin"},
    2: {"user_id": 2, "role": "user"},
    3: {"user_id": 3, "role": "user"},
    4: {"user_id": 4, "role": "user"}
}

def check_user_role(user_id: int) -> str:
    """
    Determines if a user is an admin or a regular user.

    Args:
        user_id: The ID of the user.

    Returns:
        A string indicating the user's role ("admin", "user", or "unknown").
    """
    user_info = USERS.get(user_id)
    if user_info:
        return user_info.get("role", "unknown")
    return "unknown"

if __name__ == '__main__':
    # Example usage:
    print(f"User 1 role: {check_user_role(1)}")
    print(f"User 2 role: {check_user_role(2)}")
    print(f"User 5 role: {check_user_role(5)}")

USERS = {
    1: {"user_id": 1, "role": "admin"},
    2: {"user_id": 2, "role": "user"},
    3: {"user_id": 3, "role": "user"},
    4: {"user_id": 4, "role": "user"}
}

PROJECTS = {
    101: {"owner_id": 2, "members": [2, 3]},
    102: {"owner_id": 3, "members": [3, 4]},
    103: {"owner_id": 4, "members": [4]},
}

def project_access_control(active_user_id: int, prj_id: int, action_type: str, member_user_id: int) -> bool:
    """
    Manages project membership based on user roles and ownership.

    Args:
        active_user_id: The ID of the user performing the action.
        prj_id: The ID of the project being modified.
        action_type: 'add' or 'remove'.
        member_user_id: The ID of the user to be added or removed.

    Returns:
        True if the operation was successful, False otherwise.
    """
    if active_user_id not in USERS:
        return False  # Active user does not exist

    if prj_id not in PROJECTS:
        return False  # Project does not exist

    if member_user_id not in USERS:
        return False # Member user does not exist

    active_user = USERS[active_user_id]
    project = PROJECTS[prj_id]

    is_admin = active_user["role"] == "admin"
    is_owner = project["owner_id"] == active_user_id

    if not (is_admin or is_owner):
        return False  # Not authorized

    if action_type == "add":
        if member_user_id not in project["members"]:
            project["members"].append(member_user_id)
        return True
    elif action_type == "remove":
        if member_user_id == project["owner_id"]:
            return False  # Cannot remove project owner

        if member_user_id in project["members"]:
            project["members"].remove(member_user_id)
            return True
        else:
            return False  # Member not in project, cannot remove
    else:
        return False  # Invalid action type

turn2_code:
USERS = {
    1: {"user_id": 1, "role": "admin"},
    2: {"user_id": 2, "role": "user"},
    3: {"user_id": 3, "role": "user"},
    4: {"user_id": 4, "role": "user"}
}

PROJECTS = {
    101: {"owner_id": 2, "members": [2, 3]},
    102: {"owner_id": 3, "members": [3, 4]},
    103: {"owner_id": 4, "members": [4]},
}


def _has_permission(active_user_id: int, prj_id: int, users_data: dict, projects_data: dict) -> bool:
    """Checks if the active user has permission to manage the project."""
    active_user = users_data[active_user_id]
    project = projects_data[prj_id]
    is_admin = active_user["role"] == "admin"
    is_owner = project["owner_id"] == active_user_id
    return is_admin or is_owner


def _update_project_members(project: dict, action_type: str, member_user_id: int) -> bool:
    """Adds or removes a member from the project."""
    if action_type == "add":
        if member_user_id not in project["members"]:
            project["members"].append(member_user_id)
        return True
    elif action_type == "remove":
        if member_user_id == project["owner_id"]:
            return False  # Cannot remove project owner
        if member_user_id in project["members"]:
            project["members"].remove(member_user_id)
            return True
        else:
            return False  # Member not in project, cannot remove
    return False # Invalid action type


def project_access_control(active_user_id: int, prj_id: int, action_type: str, member_user_id: int) -> bool:
    """
    Manages project membership based on user roles and ownership.

    Args:
        active_user_id: The ID of the user performing the action.
        prj_id: The ID of the project being modified.
        action_type: 'add' or 'remove'.
        member_user_id: The ID of the user to be added or removed.

    Returns:
        True if the operation was successful, False otherwise.
    """
    if active_user_id not in USERS:
        return False  # Active user does not exist

    if prj_id not in PROJECTS:
        return False  # Project does not exist

    if member_user_id not in USERS:
        return False  # Member user does not exist

    if not _has_permission(active_user_id, prj_id, USERS, PROJECTS):
        return False  # Not authorized

    project = PROJECTS[prj_id]
    return _update_project_members(project, action_type, member_user_id)
